import type { Metadata, Viewport } from "next";
import { Inter, JetBrains_Mono } from "next/font/google";
import "./globals.css";

const inter = Inter({
  variable: "--font-sans",
  subsets: ["latin"],
  display: "swap",
});

const jetbrainsMono = JetBrains_Mono({
  variable: "--font-mono",
  subsets: ["latin"],
  display: "swap",
});

export const metadata: Metadata = {
  metadataBase: new URL("https://checkers-fun.example.com"),
  title: {
    default: "Checkers Arena",
    template: "%s · Checkers Arena",
  },
  description:
    "A polished, fun, production-ready checkers app shell supporting local play, AI, online play, puzzles, timers, hints, undo/redo, and stats.",
  applicationName: "Checkers Arena",
  keywords: [
    "checkers",
    "draughts",
    "next.js",
    "board game",
    "puzzle mode",
    "multiplayer",
  ],
  authors: [{ name: "Checkers Arena Team" }],
  creator: "Checkers Arena Team",
  icons: {
    icon: "/favicon.ico",
  },
};

export const viewport: Viewport = {
  width: "device-width",
  initialScale: 1,
  maximumScale: 1,
  themeColor: [
    { media: "(prefers-color-scheme: dark)", color: "#06070d" },
    { media: "(prefers-color-scheme: light)", color: "#f7f8fc" },
  ],
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" suppressHydrationWarning>
      <body className={`${inter.variable} ${jetbrainsMono.variable} antialiased`}>
        <a href="#main-content" className="skip-link">
          Skip to main content
        </a>

        <div className="app-shell" data-theme="dark-modern">
          <div className="app-backdrop" aria-hidden="true" />

          <header className="app-header">
            <div className="container app-header-inner">
              <div className="brand-group" aria-label="Application identity">
                <span className="brand-badge" aria-hidden="true">
                  ♟
                </span>
                <div>
                  <p className="brand-kicker">Step 1 Foundation</p>
                  <h1 className="brand-title">Checkers Arena</h1>
                </div>
              </div>

              <p className="status-pill" aria-label="Build readiness status">
                Production-ready scaffold
              </p>
            </div>
          </header>

          <main id="main-content" className="app-main container">
            {children}
          </main>

          <footer className="app-footer">
            <div className="container app-footer-inner">
              <p>Built for smooth gameplay, responsive UI, and stable feature expansion.</p>
              <p className="mono">Next.js + TypeScript + Tailwind baseline</p>
            </div>
          </footer>
        </div>
      </body>
    </html>
  );
}

@import "tailwindcss";

:root {
  --font-sans: "Inter", ui-sans-serif, system-ui, -apple-system, "Segoe UI", sans-serif;
  --font-mono: "JetBrains Mono", ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;

  --radius-sm: 0.5rem;
  --radius-md: 0.875rem;
  --radius-lg: 1.25rem;
  --radius-xl: 1.75rem;

  --shadow-soft: 0 10px 30px rgba(0, 0, 0, 0.2);
  --shadow-glow: 0 0 0 1px rgba(255, 255, 255, 0.06), 0 20px 40px rgba(22, 11, 48, 0.45);

  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-6: 1.5rem;
  --space-8: 2rem;
  --space-12: 3rem;

  --bg: #06070d;
  --bg-elevated: #101223;
  --bg-card: #14182e;
  --text: #f1f4ff;
  --text-muted: #a8b0d0;
  --border: rgba(161, 172, 255, 0.22);
  --accent: #7c5cff;
  --accent-2: #2dd4bf;
  --accent-3: #ff9f43;
}

/* Theme hooks for future customization */
[data-theme="playful-colorful"] {
  --bg: #0f0720;
  --bg-elevated: #1a1033;
  --bg-card: #25154b;
  --text: #f7f3ff;
  --text-muted: #cabcf1;
  --border: rgba(255, 255, 255, 0.2);
  --accent: #ff4ecd;
  --accent-2: #22d3ee;
  --accent-3: #f59e0b;
}

[data-theme="classic-wooden"] {
  --bg: #2a1e16;
  --bg-elevated: #3a2a1f;
  --bg-card: #4c3829;
  --text: #f4eadf;
  --text-muted: #d8c1a8;
  --border: rgba(255, 219, 178, 0.25);
  --accent: #d97706;
  --accent-2: #84cc16;
  --accent-3: #f59e0b;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  min-height: 100%;
}

html {
  color-scheme: dark;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-sans);
  color: var(--text);
  background:
    radial-gradient(1200px 700px at 95% -10%, rgba(124, 92, 255, 0.2), transparent 55%),
    radial-gradient(900px 700px at 0% 110%, rgba(45, 212, 191, 0.2), transparent 55%),
    var(--bg);
  line-height: 1.55;
}

a {
  color: inherit;
  text-decoration: none;
}

img,
svg,
video,
canvas {
  display: block;
  max-width: 100%;
}

::selection {
  background: color-mix(in oklab, var(--accent) 40%, transparent);
  color: white;
}

.skip-link {
  position: absolute;
  left: -9999px;
  top: auto;
  width: 1px;
  height: 1px;
  overflow: hidden;
  z-index: 50;
}

.skip-link:focus {
  left: var(--space-4);
  top: var(--space-4);
  width: auto;
  height: auto;
  padding: 0.625rem 0.875rem;
  border-radius: var(--radius-sm);
  background: var(--accent);
  color: white;
  box-shadow: var(--shadow-soft);
}

.container {
  width: min(1120px, calc(100% - 2rem));
  margin-inline: auto;
}

.app-shell {
  position: relative;
  isolation: isolate;
  min-height: 100dvh;
  display: grid;
  grid-template-rows: auto 1fr auto;
}

.app-backdrop {
  position: fixed;
  inset: 0;
  z-index: -1;
  background:
    radial-gradient(500px 300px at 10% 5%, color-mix(in oklab, var(--accent) 22%, transparent), transparent),
    radial-gradient(700px 450px at 90% 90%, color-mix(in oklab, var(--accent-2) 20%, transparent), transparent);
  pointer-events: none;
}

.app-header {
  position: sticky;
  top: 0;
  z-index: 40;
  backdrop-filter: blur(8px);
  background: color-mix(in oklab, var(--bg) 84%, transparent);
  border-bottom: 1px solid var(--border);
}

.app-header-inner {
  min-height: 4.5rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
  padding-block: 0.75rem;
}

.brand-group {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.brand-badge {
  width: 2.35rem;
  height: 2.35rem;
  border-radius: 999px;
  display: grid;
  place-items: center;
  font-size: 1.2rem;
  background: linear-gradient(145deg, var(--accent), var(--accent-2));
  color: white;
  box-shadow: var(--shadow-glow);
}

.brand-kicker {
  margin: 0;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-muted);
}

.brand-title {
  margin: 0;
  font-size: 1rem;
  font-weight: 700;
}

.status-pill {
  margin: 0;
  font-size: 0.8rem;
  color: var(--text);
  border: 1px solid var(--border);
  border-radius: 999px;
  padding: 0.4rem 0.75rem;
  background: color-mix(in oklab, var(--bg-card) 72%, transparent);
  transition: transform 220ms ease, border-color 220ms ease, background-color 220ms ease;
}

.status-pill:hover {
  transform: translateY(-1px);
  border-color: color-mix(in oklab, var(--accent) 55%, var(--border));
  background: color-mix(in oklab, var(--accent) 12%, var(--bg-card));
}

.app-main {
  padding-block: clamp(1rem, 2.5vw, 2rem);
}

.app-footer {
  border-top: 1px solid var(--border);
  background: color-mix(in oklab, var(--bg) 88%, transparent);
}

.app-footer-inner {
  min-height: 3.5rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
  flex-wrap: wrap;
  padding-block: 0.875rem;
  color: var(--text-muted);
  font-size: 0.875rem;
}

.mono {
  font-family: var(--font-mono);
  letter-spacing: 0.01em;
  font-size: 0.8rem;
}

@media (max-width: 900px) {
  .status-pill {
    display: none;
  }

  .app-footer-inner {
    justify-content: center;
    text-align: center;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}
